import{_ as e,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Solução de Invalid Grant: Recuperação de Conta Desativada | Antigravity-Manager","description":"Aprenda o significado do erro invalid_grant e a lógica de processamento automático. Confirme que o refresh_token expirou, recupere a conta adicionando OAuth novamente para acionar o desbloqueio automático, e verifique que a recuperação afeta o Proxy.","frontmatter":{"title":"Solução de Invalid Grant: Recuperação de Conta Desativada | Antigravity-Manager","sidebarTitle":"Como Recuperar Conta Desativada","subtitle":"invalid_grant e Desativação Automática de Conta: Por Que Ocorre, Como Recuperar","description":"Aprenda o significado do erro invalid_grant e a lógica de processamento automático. Confirme que o refresh_token expirou, recupere a conta adicionando OAuth novamente para acionar o desbloqueio automático, e verifique que a recuperação afeta o Proxy.","tags":["FAQ","Solução de Problemas","OAuth","Gerenciamento de Contas","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function n(s,a,d,c,l,u){return t(),o("div",null,[...a[0]||(a[0]=[r(`<h1 id="invalid-grant-e-desativacao-automatica-de-conta-por-que-ocorre-como-recuperar" tabindex="-1">invalid_grant e Desativação Automática de Conta: Por Que Ocorre, Como Recuperar <a class="header-anchor" href="#invalid-grant-e-desativacao-automatica-de-conta-por-que-ocorre-como-recuperar" aria-label="Permalink to &quot;invalid_grant e Desativação Automática de Conta: Por Que Ocorre, Como Recuperar&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-este-curso" tabindex="-1">O Que Você Poderá Fazer Após Este Curso <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-este-curso" aria-label="Permalink to &quot;O Que Você Poderá Fazer Após Este Curso&quot;">​</a></h2><ul><li>Ao ver <code>invalid_grant</code>, saber qual categoria de problema de refresh_token corresponde</li><li>Entender claramente &quot;por que a conta de repente ficou indisponível&quot;: em quais situações será desativada automaticamente, como o sistema lida após a desativação</li><li>Recuperar a conta pelo caminho mais curto e confirmar que a recuperação já afetou o Proxy em execução</li></ul><h2 id="seus-sintomas" tabindex="-1">Seus Sintomas <a class="header-anchor" href="#seus-sintomas" aria-label="Permalink to &quot;Seus Sintomas&quot;">​</a></h2><ul><li>Ao chamar o Proxy local, de repente falha, a mensagem de erro contém <code>invalid_grant</code></li><li>A conta ainda está na lista de Accounts, mas o Proxy sempre a pula (ou você sente que &quot;nunca mais foi usada&quot;)</li><li>Com poucas contas, após encontrar <code>invalid_grant</code> uma vez, a disponibilidade geral piora visivelmente</li></ul><h2 id="o-que-e-invalid-grant" tabindex="-1">O Que é invalid_grant? <a class="header-anchor" href="#o-que-e-invalid-grant" aria-label="Permalink to &quot;O Que é invalid_grant?&quot;">​</a></h2><p><strong>invalid_grant</strong> é uma categoria de erro retornada pelo Google OAuth ao atualizar <code>access_token</code>. Para o Antigravity Tools, significa que o <code>refresh_token</code> de certa conta provavelmente foi revogado ou expirou, continuar tentando apenas falhará repetidamente, então o sistema marcará essa conta como indisponível e a removerá do pool de proxy.</p><h2 id="ideia-central-o-sistema-nao-pula-temporariamente-mas-desativa-permanentemente" tabindex="-1">Ideia Central: O Sistema Não &quot;Pula Temporariamente&quot;, Mas &quot;Desativa Permanentemente&quot; <a class="header-anchor" href="#ideia-central-o-sistema-nao-pula-temporariamente-mas-desativa-permanentemente" aria-label="Permalink to &quot;Ideia Central: O Sistema Não &quot;Pula Temporariamente&quot;, Mas &quot;Desativa Permanentemente&quot;&quot;">​</a></h2><p>Quando o Proxy descobre que a string de erro ao atualizar o token contém <code>invalid_grant</code>, fará duas coisas:</p><ol><li><strong>Escrever a conta como disabled</strong> (persistir no JSON da conta)</li><li><strong>Remover a conta do pool de tokens na memória</strong> (evitar selecionar repetidamente a mesma conta ruim)</li></ol><p>É por isso que você vê &quot;a conta ainda existe, mas o Proxy não a usa mais&quot;.</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>: A conta foi &quot;completamente desativada&quot; (motivo típico é <code>invalid_grant</code>). Ao carregar o pool de contas, será pulada diretamente.</li><li><code>proxy_disabled=true</code>: A conta é apenas &quot;indisponível para o Proxy&quot; (desativação manual/operação em lote/lógica relacionada à proteção de cota), semântica diferente.</li></ul><p>Esses dois estados são julgados separadamente ao carregar o pool de contas: primeiro julga <code>disabled</code>, depois faz a proteção de cota e o julgamento de <code>proxy_disabled</code>.</p></div><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-confirme-se-e-invalid-grant-disparado-pela-atualizacao-de-refresh-token" tabindex="-1">Passo 1: Confirme se é invalid_grant Disparado pela Atualização de refresh_token <a class="header-anchor" href="#passo-1-confirme-se-e-invalid-grant-disparado-pela-atualizacao-de-refresh-token" aria-label="Permalink to &quot;Passo 1: Confirme se é invalid_grant Disparado pela Atualização de refresh_token&quot;">​</a></h3><p><strong>Por Que</strong>: <code>invalid_grant</code> pode aparecer em múltiplas cadeias de chamada, mas a &quot;desativação automática&quot; deste projeto só é disparada quando a <strong>atualização de access_token falha</strong>.</p><p>No log do Proxy, você verá logs de erro semelhantes (palavras-chave são <code>Token 刷新失败</code> + <code>invalid_grant</code>):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 刷新失败 (&lt;email&gt;): &lt;...invalid_grant...&gt;，尝试下一个账号</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>Você Deve Ver</strong>: A mesma conta logo após aparecer <code>invalid_grant</code>, não será mais selecionada (porque foi removida do token pool).</p><h3 id="passo-2-verifique-o-campo-disabled-no-arquivo-da-conta-opcional-mais-preciso" tabindex="-1">Passo 2: Verifique o Campo disabled no Arquivo da Conta (Opcional, Mais Preciso) <a class="header-anchor" href="#passo-2-verifique-o-campo-disabled-no-arquivo-da-conta-opcional-mais-preciso" aria-label="Permalink to &quot;Passo 2: Verifique o Campo disabled no Arquivo da Conta (Opcional, Mais Preciso)&quot;">​</a></h3><p><strong>Por Que</strong>: A desativação automática é &quot;persistente&quot;, após confirmar o conteúdo do arquivo, você pode excluir o julgamento errado de &quot;apenas rotação temporária&quot;.</p><p>O arquivo da conta está localizado no diretório <code>accounts/</code> do diretório de dados do aplicativo (a localização do diretório de dados veja <strong><a href="./../../start/first-run-data/">Primeira Inicialização: Diretório de Dados, Logs, Bandeja e Inicialização Automática</a></strong>). Quando a conta é desativada, o arquivo aparecerá com estes três campos:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Você Deve Ver</strong>: <code>disabled</code> é <code>true</code>, e <code>disabled_reason</code> contém o prefixo <code>invalid_grant:</code>.</p><h3 id="passo-3-recupere-a-conta-recomendado-adicione-a-mesma-conta-novamente" tabindex="-1">Passo 3: Recupere a Conta (Recomendado: Adicione a Mesma Conta Novamente) <a class="header-anchor" href="#passo-3-recupere-a-conta-recomendado-adicione-a-mesma-conta-novamente" aria-label="Permalink to &quot;Passo 3: Recupere a Conta (Recomendado: Adicione a Mesma Conta Novamente)&quot;">​</a></h3><p><strong>Por Que</strong>: A &quot;recuperação&quot; deste projeto não é clicar um interruptor no Proxy, mas acionar o desbloqueio automático através de &quot;atualização explícita de token&quot;.</p><p>Vá para a página <strong>Accounts</strong>, adicione a conta novamente com suas novas credenciais (escolha um dos dois métodos):</p><ol><li>Execute o processo de autorização OAuth novamente (veja <strong><a href="./../../start/add-account/">Adicionar Contas: Canal Duplo OAuth/Refresh Token e Melhores Práticas</a></strong>)</li><li>Adicione novamente com o novo <code>refresh_token</code> (o sistema usará o email retornado pelo Google como base para fazer upsert)</li></ol><p>Quando o sistema detecta que o <code>refresh_token</code> ou <code>access_token</code> deste upsert é diferente do valor antigo, e a conta anteriormente estava em <code>disabled=true</code>, limpará automaticamente:</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>Você Deve Ver</strong>: A conta não está mais no estado disabled, e (se o Proxy estiver em execução) o pool de contas será recarregado automaticamente, fazendo a recuperação entrar em vigor imediatamente.</p><h3 id="passo-4-verifique-se-a-recuperacao-ja-afetou-o-proxy" tabindex="-1">Passo 4: Verifique se a Recuperação Já Afetou o Proxy <a class="header-anchor" href="#passo-4-verifique-se-a-recuperacao-ja-afetou-o-proxy" aria-label="Permalink to &quot;Passo 4: Verifique se a Recuperação Já Afetou o Proxy&quot;">​</a></h3><p><strong>Por Que</strong>: Se você só tem uma conta, ou outras contas também estão indisponíveis, após a recuperação você deve ver imediatamente &quot;a disponibilidade voltou&quot;.</p><p>Método de verificação:</p><ol><li>Faça uma solicitação que dispare a atualização de token (por exemplo, aguarde o token próximo de expirar antes de solicitar)</li><li>Observe que o log não aparece mais a dica &quot;pular conta disabled&quot;</li></ol><p><strong>Você Deve Ver</strong>: Solicitação passa normalmente, e o log não aparece mais o processo de desativação <code>invalid_grant</code> para essa conta.</p><h2 id="lembrete-de-armadilhas" tabindex="-1">Lembrete de Armadilhas <a class="header-anchor" href="#lembrete-de-armadilhas" aria-label="Permalink to &quot;Lembrete de Armadilhas&quot;">​</a></h2><h3 id="❌-tratar-disabled-como-rotacao-temporaria" tabindex="-1">❌ Tratar disabled como &quot;Rotação Temporária&quot; <a class="header-anchor" href="#❌-tratar-disabled-como-rotacao-temporaria" aria-label="Permalink to &quot;❌ Tratar disabled como &quot;Rotação Temporária&quot;&quot;">​</a></h3><p>Se você só vê na UI &quot;a conta ainda existe&quot;, é fácil julgar erroneamente como &quot;o sistema apenas não a usa temporariamente&quot;. Mas <code>disabled=true</code> é escrito no disco, continuará em vigor após reiniciar.</p><h3 id="❌-apenas-suplementar-access-token-nao-atualizar-refresh-token" tabindex="-1">❌ Apenas Suplementar access_token, Não Atualizar refresh_token <a class="header-anchor" href="#❌-apenas-suplementar-access-token-nao-atualizar-refresh-token" aria-label="Permalink to &quot;❌ Apenas Suplementar access_token, Não Atualizar refresh_token&quot;">​</a></h3><p>O ponto de gatilho de <code>invalid_grant</code> é o <code>refresh_token</code> usado ao atualizar <code>access_token</code>. Se você apenas obteve temporariamente um <code>access_token</code> ainda utilizável, mas <code>refresh_token</code> ainda expirou, subsequentemente ainda disparará a desativação.</p><h2 id="pontos-de-verificacao-✅" tabindex="-1">Pontos de Verificação ✅ <a class="header-anchor" href="#pontos-de-verificacao-✅" aria-label="Permalink to &quot;Pontos de Verificação ✅&quot;">​</a></h2><ul><li>[ ] Você pode confirmar no log que <code>invalid_grant</code> vem da falha de atualização de refresh_token</li><li>[ ] Você sabe a diferença semântica entre <code>disabled</code> e <code>proxy_disabled</code></li><li>[ ] Você pode recuperar a conta adicionando novamente (OAuth ou refresh_token)</li><li>[ ] Você pode verificar que a recuperação já afetou o Proxy em execução</li></ul><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><ul><li>Quando <code>invalid_grant</code> é disparado, o Proxy <strong>persistirá a conta como disabled</strong> e a removerá do token pool, evitando falhas repetidas</li><li>A chave da recuperação é &quot;atualização explícita de token&quot; (OAuth novamente ou adicionar novamente com novo refresh_token), o sistema limpará automaticamente os campos <code>disabled_*</code></li><li>O JSON da conta no diretório de dados é a fonte mais autoritária de estado (desativação/motivo/tempo estão dentro)</li></ul><h2 id="proximo-passo" tabindex="-1">Próximo Passo <a class="header-anchor" href="#proximo-passo" aria-label="Permalink to &quot;Próximo Passo&quot;">​</a></h2><blockquote><p>Na próxima lição aprenderemos <strong><a href="./../auth-401/">401/Falha de Autenticação: auth_mode, Compatibilidade de Header e Lista de Verificação de Configuração de Cliente</a></strong>.</p><p>Você aprenderá:</p><ul><li>401 geralmente é qual camada não corresponde entre &quot;modo/Key/Header&quot;</li><li>Quais Headers de autenticação diferentes clientes devem trazer</li><li>Como fazer autodiagnóstico e reparo pelo caminho mais curto</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-fonte&quot;">​</a></h2><details><summary><strong>Clique para Expandir e Ver Localização do Código-fonte</strong></summary><blockquote><p>Última Atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Função</th><th>Caminho do Arquivo</th><th>Número da Linha</th></tr></thead><tbody><tr><td>Explicação de Design: Problema de invalid_grant e Comportamento de Mudança</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>Ao carregar o pool de contas, pular <code>disabled=true</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>Ao falhar a atualização de token, identificar <code>invalid_grant</code> e desativar conta</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td>Persistir gravar <code>disabled/disabled_at/disabled_reason</code> e remover da memória</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td>Truncamento de <code>disabled_reason</code> (evitar inflar arquivo de conta)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>Ao upsert, limpar automaticamente <code>disabled_*</code> (mudança de token vista como usuário corrigiu credenciais)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>Após adicionar conta novamente, recarregar automaticamente contas de proxy (entra em vigor imediatamente em execução)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const h=e(i,[["render",n]]);export{m as __pageData,h as default};
